import{_ as e,o as r,c as t,ai as s}from"./chunks/framework.CaiDwmc7.js";const h=JSON.parse('{"title":"消息丢失的终极防线","description":"","frontmatter":{},"headers":[],"relativePath":"mq/message-loss.md","filePath":"mq/message-loss.md"}'),n={name:"mq/message-loss.md"};function a(l,o,i,c,g,d){return r(),t("div",null,[...o[0]||(o[0]=[s('<h1 id="消息丢失的终极防线" tabindex="-1">消息丢失的终极防线 <a class="header-anchor" href="#消息丢失的终极防线" aria-label="Permalink to “消息丢失的终极防线”">​</a></h1><hr><h3 id="❓-面试官-引入-mq-后-怎么保证消息绝对不丢失-以-rocketmq-rabbitmq-为例" tabindex="-1">❓ 面试官：引入 MQ 后，怎么保证消息绝对不丢失？（以 RocketMQ / RabbitMQ 为例） <a class="header-anchor" href="#❓-面试官-引入-mq-后-怎么保证消息绝对不丢失-以-rocketmq-rabbitmq-为例" aria-label="Permalink to “❓ 面试官：引入 MQ 后，怎么保证消息绝对不丢失？（以 RocketMQ / RabbitMQ 为例）”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 一条消息从产生到被消费，会经历三个阶段，这三个阶段都可能丢消息。我们必须做到：<strong>生产者采用带确认的同步发送机制 + MQ 服务端开启同步刷盘和主从同步复制 + 消费者关闭自动 ACK 采用手动确认机制</strong>，这样才能保证消息绝对不丢失。</p><p><strong>📝 详细三个阶段的防丢失策略实战：</strong></p><h4 id="第一关-生产者发送阶段丢失" tabindex="-1">第一关：生产者发送阶段丢失 <a class="header-anchor" href="#第一关-生产者发送阶段丢失" aria-label="Permalink to “第一关：生产者发送阶段丢失”">​</a></h4><ul><li><strong>丢失场景</strong>：网络突然抖动，代码里调了 <code>send()</code> 以为发成功了，其实 MQ 根本没收到。</li><li><strong>解决方案（RocketMQ 为例）</strong>： <ol><li><strong>放弃异步/单向发送</strong>：核心业务必须使用<strong>同步发送（Sync Send）</strong>。</li><li><strong>判断发送状态</strong>：调用 <code>send()</code> 后，必须同步拿到一个 <code>SendResult</code> 对象。判断它的状态是不是 <code>SEND_OK</code>。</li><li><strong>重试与兜底方案</strong>：如果不是 <code>OK</code> 或者抛了超时异常，触发重试机制（默认重试 2 次）。如果重试 3 次依然失败，必须<strong>捕获异常，把这条本该发送的消息记录到数据库的“消息发送失败表”中</strong>，然后由后台定时任务轮询补偿发送，确保第一关绝对不丢。</li></ol></li></ul><h4 id="第二关-mq-服务端-broker-存储阶段丢失" tabindex="-1">第二关：MQ 服务端（Broker）存储阶段丢失 <a class="header-anchor" href="#第二关-mq-服务端-broker-存储阶段丢失" aria-label="Permalink to “第二关：MQ 服务端（Broker）存储阶段丢失”">​</a></h4><ul><li><strong>丢失场景</strong>：MQ 确实收到了消息，先放进了系统内存（PageCache），正准备写到磁盘上时，MQ 所在的服务器突然断电/宕机，内存里的数据瞬间蒸发。</li><li><strong>解决方案</strong>： <ol><li><strong>修改刷盘策略（牺牲性能保安全）</strong>：把 MQ 默认的<code>异步刷盘（ASYNC_FLUSH）</code>改为<strong><code>同步刷盘（SYNC_FLUSH）</code></strong>。这意味着，只有当这条消息确确实实写死到了硬盘上，MQ 才会给生产者返回 <code>SEND_OK</code>。</li><li><strong>修改主从同步策略</strong>：如果是集群部署，只有主节点写盘成功不够，万一主节点的硬盘直接烧了呢？把主从同步策略从<code>异步复制</code>改为<strong><code>同步双写（SYNC_MASTER）</code></strong>。只有当主节点和从节点都把数据写到硬盘了，才算真的发送成功。</li></ol></li></ul><h4 id="第三关-消费者消费阶段丢失-极其容易踩坑" tabindex="-1">第三关：消费者消费阶段丢失（极其容易踩坑） <a class="header-anchor" href="#第三关-消费者消费阶段丢失-极其容易踩坑" aria-label="Permalink to “第三关：消费者消费阶段丢失（极其容易踩坑）”">​</a></h4><ul><li><strong>丢失场景</strong>：消费者刚从 MQ 拉到消息，还没来得及执行业务逻辑（比如写数据库），代码里突然抛了个空指针异常，或者消费者服务器直接被 kill 掉了。但 MQ 以为你消费成功了，就把消息从队列里删了。</li><li><strong>解决方案</strong>： <ul><li><strong>核心原则：关闭自动 ACK，改为手动 ACK</strong>。</li><li><strong>Spring Boot 落地</strong>：在监听器里，必须是你的业务逻辑<strong>全部执行成功（比如数据库 commit 成功）</strong>后，才手动给 MQ 返回 <code>Action.CommitMessage</code> 或 <code>ConsumeConcurrentlyStatus.CONSUME_SUCCESS</code>。</li><li>如果抛了异常，应该被 <code>catch</code> 住，返回 <code>RECONSUME_LATER</code>（稍后重试），MQ 会把这条消息放回重试队列，等会儿再发给你，绝对不会因为异常而直接丢弃消息。</li></ul></li></ul><p><strong>🌟 面试加分项（实战血泪教训）：</strong> &quot;面试官您好，理论上做到上面三步确实能保证不丢，但这会导致系统的<strong>吞吐量产生断崖式的下跌</strong>（全是同步和等磁盘 IO）。 在我们真实的电商支付链路中，为了兼顾高并发，我们 MQ 服务端依然保留了<strong>异步刷盘</strong>。那万一宕机丢了怎么办？ 我们引入了<strong>对账机制（兜底王牌）</strong>。我们会用一个定时任务，每隔 5 分钟去比对“订单库”和“支付库”的数据。一旦发现订单状态是已支付，但支付库没有对应的流水（说明丢了通知消息），就会通过对账程序<strong>自动发起状态补偿和重试</strong>。这才是大厂高并发下容忍一定故障但保证最终一致性的真实解法。&quot;</p>',13)])])}const _=e(n,[["render",a]]);export{h as __pageData,_ as default};
